import { type Address, encodeFunctionData, type Hex } from 'viem'
import { conditionalTokenAbi } from '../../abis/conditionalToken'

export type RedeemPositionsParams = {
  collateralToken: Address
  parentCollectionId: Hex
  conditionId: Hex
  indexSets: bigint[]
}

export function redeemPositionsCalldata(params: RedeemPositionsParams): Hex {
  return encodeFunctionData({
    abi: conditionalTokenAbi,
    functionName: 'redeemPositions',
    args: [
      params.collateralToken,
      params.parentCollectionId,
      params.conditionId,
      params.indexSets,
    ],
  })
}
