import type { Address, Hex } from 'viem'

export enum OrderStructSide {
  Buy = 0,
  Sell = 1,
}

export enum OrderStructSignatureType {
  Eoa = 0,
  ProbProxy = 1,
  ProbGnosisSafe = 2,
}

export type OrderStruct = {
  /**
   * Unique salt to ensure entropy
   */
  salt: bigint
  /**
   * Maker of the order
   * i.e the source of funds for the order
   */
  maker: Address
  /**
   * Signer of the order
   */
  signer: Address
  /**
   * Address of the order taker. The zero address is used to indicate a public order
   */
  taker: Address
  /**
   * Token Id of the CTF ERC1155 asset to be bought or sold.
   * If BUY, this is the tokenId of the asset to be bought, i.e the makerAssetId
   * If SELL, this is the tokenId of the asset to be sold, i.e the  takerAssetId
   */
  tokenId: bigint
  /**
   * Maker amount, i.e the max amount of tokens to be sold
   */
  makerAmount: bigint
  /**
   * Taker amount, i.e the minimum amount of tokens to be received
   */
  takerAmount: bigint
  /**
   * Timestamp after which the order is expired
   */
  expiration: bigint
  /**
   * Nonce used for onchain cancellations
   */
  nonce: bigint
  /**
   * Fee rate, in basis points, charged to the order maker, charged on proceeds
   */
  feeRateBps: bigint
  /**
   * The side of the order, BUY or SELL
   */
  side: OrderStructSide
  /**
   * Signature type used by the Order:
   * - EOA: EOA signature
   * - PROB_PROXY: PROB Proxy signature
   * - PROB_GNOSIS_SAFE: PROB Gnosis Safe signature
   */
  signatureType: OrderStructSignatureType
  /**
   * Signature of the order
   */
  signature: Hex
  /**
   * Price slippage tolerance for the order
   *
   * only for market orders
   * if sell order, the price slippage tolerance is the maximum price order will be executed at
   * if buy order, the price slippage tolerance is the minimum price order will be executed at
   */
  priceLimit?: number
}

