import type { Address, PublicClient } from 'viem'
import { type Addresses, addresses } from '../constants/addresses'

export function getAddressFromClient(
  publicClient: PublicClient,
  key: keyof Addresses,
): Address | undefined {
  const chainId = publicClient.chain?.id as number
  if (!chainId) return undefined
  return addresses[chainId]?.[key]
}
