import { exchangeConfig } from '../../../constants/exchangeConfig'
import {
  InvalidFeeRateError,
  InvalidSignatureError,
  OrderExpiredError,
} from '../../../errors'
import type { OrderStruct } from '../../../structs'
import { hashOrder } from './hashOrder'
import { validateOrderSignature } from './validateOrderSignature'

export async function validateOrder(chainId: number, order: OrderStruct) {
  const { expiration } = order

  const orderHash = hashOrder(chainId, order)

  if (expiration > 0 && expiration < Date.now() / 1000) {
    throw new OrderExpiredError(`order expired at ${expiration}`)
  }

  const validSignature = await validateOrderSignature(chainId, orderHash, order)
  if (!validSignature) {
    throw new InvalidSignatureError(`invalid signature for order ${orderHash}`)
  }

  const maxFeeRate = exchangeConfig[chainId].maxFeeRate
  if (order.feeRateBps > maxFeeRate) {
    throw new InvalidFeeRateError(
      `fee rate ${order.feeRateBps} is greater than max fee rate ${maxFeeRate}`,
    )
  }

  // bypass validate token-id / nonce / order-status
  // as it cannot be validated off-chain

  return {
    isValid: true,
    orderHash,
    order,
  }
}
