import type { Address, Hex } from 'viem'
import { encodeFunctionData } from 'viem'
import { conditionalTokenAbi } from '../../abis/conditionalToken'

export type MergePositionsParams = {
  collateralToken: Address
  parentCollectionId: Hex
  conditionId: Hex
  partition: bigint[]
  amount: bigint
}

export function mergePositionsCalldata(params: MergePositionsParams): Hex {
  if (params.partition.length < 1)
    throw new Error('Got empty or singleton partition')

  return encodeFunctionData({
    abi: conditionalTokenAbi,
    functionName: 'mergePositions',
    args: [
      params.collateralToken,
      params.parentCollectionId,
      params.conditionId,
      params.partition,
      params.amount,
    ],
  })
}
