import { encodePacked, type Hex, keccak256 } from 'viem'

// alt_bn128 curve parameters
const P = BigInt(
  '21888242871839275222246405745257275088696311157297823662689037894645226208583',
)
const B = BigInt(3)
const ODD_TOGGLE = BigInt(1) << BigInt(254)

// Modular arithmetic helper functions
function mod(a: bigint, m: bigint): bigint {
  return ((a % m) + m) % m
}

function addmod(a: bigint, b: bigint, m: bigint): bigint {
  return mod(a + b, m)
}

function mulmod(a: bigint, b: bigint, m: bigint): bigint {
  return mod(a * b, m)
}

// Modular exponentiation (a^b mod m)
function modPow(base: bigint, exp: bigint, m: bigint): bigint {
  let result = BigInt(1)
  base = mod(base, m)
  while (exp > 0) {
    if (exp % BigInt(2) === BigInt(1)) {
      result = mulmod(result, base, m)
    }
    exp = exp >> BigInt(1)
    base = mulmod(base, base, m)
  }
  return result
}

// Compute modular square root using Tonelli-Shanks algorithm
// Since P = 3 mod 4, we can use the simpler formula: (n^((P+1)/4)) mod P
function sqrt(n: bigint, p: bigint): bigint {
  const exp = (p + BigInt(1)) / BigInt(4)
  return modPow(n, exp, p)
}

// Elliptic curve point addition (manual implementation)
function ecAdd(
  x1: bigint,
  y1: bigint,
  x2: bigint,
  y2: bigint,
): [bigint, bigint] {
  // If first point is point at infinity
  if (x1 === BigInt(0) && y1 === BigInt(0)) {
    return [x2, y2]
  }

  // If second point is point at infinity
  if (x2 === BigInt(0) && y2 === BigInt(0)) {
    return [x1, y1]
  }

  // If points are equal, use point doubling
  if (x1 === x2 && y1 === y2) {
    return ecDouble(x1, y1)
  }

  // If x1 === x2 but y1 !== y2, result is point at infinity
  if (x1 === x2) {
    return [BigInt(0), BigInt(0)]
  }

  // Standard point addition formula
  const s = mulmod(
    addmod(y2, P - y1, P),
    modPow(addmod(x2, P - x1, P), P - BigInt(2), P),
    P,
  )
  const x3 = addmod(addmod(mulmod(s, s, P), P - x1, P), P - x2, P)
  const y3 = addmod(mulmod(s, addmod(x1, P - x3, P), P), P - y1, P)

  return [x3, y3]
}

// Elliptic curve point doubling
function ecDouble(x: bigint, y: bigint): [bigint, bigint] {
  const s = mulmod(
    mulmod(BigInt(3), mulmod(x, x, P), P),
    modPow(mulmod(BigInt(2), y, P), P - BigInt(2), P),
    P,
  )
  const x3 = addmod(mulmod(s, s, P), mulmod(BigInt(-2), x, P), P)
  const y3 = addmod(mulmod(s, addmod(x, P - x3, P), P), P - y, P)
  return [x3, y3]
}

/**
 * Constructs an outcome collection ID from a parent collection and an outcome collection.
 * @param parentCollectionId Collection ID of the parent outcome collection, or bytes32(0) if there's no parent.
 * @param conditionId Condition ID of the outcome collection to combine with the parent outcome collection.
 * @param indexSet Index set of the outcome collection to combine with the parent outcome collection.
 * @returns Collection ID (bytes32)
 */
export function getCollectionId(
  parentCollectionId: Hex,
  conditionId: Hex,
  indexSet: bigint,
): Hex {
  // Step 1: Compute initial hash
  const initHash = keccak256(
    encodePacked(['bytes32', 'uint256'], [conditionId, indexSet]),
  )

  let x1 = BigInt(initHash)
  const odd = x1 >> BigInt(255) !== BigInt(0)

  // Step 2: Find point (x1, y1) on the elliptic curve
  let y1: bigint
  let yy: bigint

  do {
    x1 = addmod(x1, BigInt(1), P)
    yy = addmod(mulmod(x1, mulmod(x1, x1, P), P), B, P)
    y1 = sqrt(yy, P)
  } while (mulmod(y1, y1, P) !== yy)

  // Adjust y1 parity
  if (
    (odd && y1 % BigInt(2) === BigInt(0)) ||
    (!odd && y1 % BigInt(2) === BigInt(1))
  ) {
    y1 = P - y1
  }

  // Step 3: Handle parent collection ID
  let x2 = BigInt(parentCollectionId)

  if (x2 !== BigInt(0)) {
    const odd2 = x2 >> BigInt(254) !== BigInt(0)
    x2 = (x2 << BigInt(2)) >> BigInt(2) // Clear top 2 bits

    yy = addmod(mulmod(x2, mulmod(x2, x2, P), P), B, P)
    let y2 = sqrt(yy, P)

    // Verify square root
    if (mulmod(y2, y2, P) !== yy) {
      throw new Error('invalid parent collection ID')
    }

    // Adjust y2 parity
    if (
      (odd2 && y2 % BigInt(2) === BigInt(0)) ||
      (!odd2 && y2 % BigInt(2) === BigInt(1))
    ) {
      y2 = P - y2
    }
    // Elliptic curve point addition
    ;[x1, y1] = ecAdd(x1, y1, x2, y2)
  }

  // Step 4: Encode result
  if (y1 % BigInt(2) === BigInt(1)) {
    x1 = x1 ^ ODD_TOGGLE
  }

  // Convert to bytes32 (Hex)
  return encodePacked(['uint256'], [x1]) as Hex
}
