import {
  type Address,
  encodeAbiParameters,
  encodePacked,
  getCreate2Address,
  keccak256,
} from 'viem'
import { addresses } from '../../../constants/addresses'
import { SAFE_PROXY_CREATION_CODE } from '../../../constants/bytecode'

export function getSafeAddress(chainId: number, signer: Address): Address {
  const safeProxyFactoryAddress = addresses[chainId]?.safeProxyFactory
  if (!safeProxyFactoryAddress)
    throw new Error('Safe Proxy Factory Address Not Found')
  const safeProxyFactoryImplementationAddress =
    addresses[chainId]?.safeProxyFactoryImplementation
  if (!safeProxyFactoryImplementationAddress)
    throw new Error('Safe Proxy Factory Implementation Address Not Found')

  return getCreate2Address({
    bytecodeHash: keccak256(
      getContractByteCode(safeProxyFactoryImplementationAddress),
    ),
    from: safeProxyFactoryAddress,
    salt: keccak256(encodeAbiParameters([{ type: 'address' }], [signer])),
  })
}

function getContractByteCode(implementationAddress: Address) {
  return encodePacked(
    ['bytes', 'bytes'],
    [
      SAFE_PROXY_CREATION_CODE,
      encodeAbiParameters([{ type: 'address' }], [implementationAddress]),
    ],
  )
}
