import { type Address, type Hex, isAddressEqual, recoverAddress } from 'viem'
import { InvalidSignatureError } from '../../../errors'
import { type OrderStruct, OrderStructSignatureType } from '../../../structs'
import { getProbProxyWalletAddress } from '../probProxy/getProbProxyWalletAddress'
import { getSafeAddress } from '../safeProxy/getSafeAddress'

export async function validateOrderSignature(
  chainId: number,
  orderHash: Hex,
  order: OrderStruct,
): Promise<boolean> {
  const { signer, maker, signature, signatureType } = order
  const validationBody: ValidationBody = {
    signer,
    maker,
    structHash: orderHash,
    signature,
  }

  switch (signatureType) {
    case OrderStructSignatureType.Eoa:
      return validateOrderSignatureEOA(validationBody)
    case OrderStructSignatureType.ProbProxy:
      return validateOrderSignaturePROBProxy(chainId, validationBody)
    case OrderStructSignatureType.ProbGnosisSafe:
      return validateOrderSignaturePROBGnosisSafe(chainId, validationBody)
    default:
      throw new InvalidSignatureError(
        `Invalid signature type: ${signatureType}`,
      )
  }
}

type ValidationBody = {
  signer: Address
  maker: Address
  structHash: Hex
  signature: Hex
}

export async function validateOrderSignatureEOA({
  signer,
  maker,
  structHash,
  signature,
}: ValidationBody): Promise<boolean> {
  if (signer !== maker) return false

  const recoveredSigner = await recoverAddress({ hash: structHash, signature })

  return isAddressEqual(recoveredSigner, signer)
}

export async function validateOrderSignaturePROBProxy(
  chainId: number,
  { signer, maker, structHash, signature }: ValidationBody,
): Promise<boolean> {
  const recoveredSigner = await recoverAddress({ hash: structHash, signature })
  const isSameSigner = isAddressEqual(recoveredSigner, signer)
  const proxyWalletAddress = await getProbProxyWalletAddress(chainId, signer)

  return isSameSigner && isAddressEqual(signer, proxyWalletAddress)
}

export async function validateOrderSignaturePROBGnosisSafe(
  chainId: number,
  { signer, maker, structHash, signature }: ValidationBody,
): Promise<boolean> {
  const recoveredSigner = await recoverAddress({ hash: structHash, signature })
  const isSameSigner = isAddressEqual(recoveredSigner, signer)
  const safeAddress = await getSafeAddress(chainId, signer)

  return isSameSigner && isAddressEqual(signer, safeAddress)
}
