import type { Address, PublicClient } from 'viem'
import { ctfExchangeAbi } from '../../abis/ctfExchange'
import { getAddressFromClient } from '../../utils/getAddressFromClient'

export async function getNonce(
  publicClient: PublicClient,
  address: Address,
): Promise<bigint> {
  const exchangeAddress = getAddressFromClient(publicClient, 'ctfExchange')
  if (!exchangeAddress) throw new Error('Exchange Address Not Found')

  const nonce = await publicClient.readContract({
    address: exchangeAddress,
    abi: ctfExchangeAbi,
    functionName: 'nonces',
    args: [address],
  })

  return nonce
}
