import { type Address, encodePacked, type Hex, keccak256 } from 'viem'

export function getConditionId(
  oracle: Address,
  questionId: Hex,
  outcomeSlotCount: bigint,
): Hex {
  return keccak256(
    encodePacked(
      ['address', 'bytes32', 'uint256'],
      [oracle, questionId, outcomeSlotCount],
    ),
  )
}
