import { type Address, erc20Abi, type PublicClient } from 'viem'
import { ctfExchangeAbi } from '../../abis/ctfExchange'
import { addresses } from '../../constants/addresses'
import {
  type ExchangeConfig,
  exchangeConfig,
} from '../../constants/exchangeConfig'

export function getExchangeConfig(chainId: number): ExchangeConfig {
  if (chainId in exchangeConfig) {
    return exchangeConfig[chainId]
  }

  throw new Error('Exchange Config Not Found')
}

export async function getExchangeConfigOnChain(
  publicClient: PublicClient,
): Promise<ExchangeConfig> {
  const chainId = publicClient.chain?.id as number
  if (!chainId) throw new Error('ChainId Not Found')
  const exchangeAddress = addresses[chainId].ctfExchange
  if (!exchangeAddress) throw new Error('Exchange Address Not Found')

  const calls = [
    {
      address: exchangeAddress,
      abi: ctfExchangeAbi,
      functionName: 'getCollateral',
    },
    {
      address: exchangeAddress,
      abi: ctfExchangeAbi,
      functionName: 'getMaxFeeRate',
    },
  ] as const

  const results = await publicClient.multicall({
    contracts: calls,
    allowFailure: false,
  })
  const [collateralToken, maxFeeRate] = results
  const collateralTokenDecimals = await publicClient.readContract({
    address: collateralToken as Address,
    abi: erc20Abi,
    functionName: 'decimals',
  })

  // Get local config for feeMultiplier and minFeeRateBps if available, otherwise use defaults
  const localConfig = chainId in exchangeConfig ? exchangeConfig[chainId] : null

  return {
    collateralToken,
    collateralTokenDecimals,
    maxFeeRate,
    feeRateBps: localConfig?.feeRateBps ?? 175n,
    feeMultiplier: localConfig?.feeMultiplier ?? 7,
    minFeeRateBps: localConfig?.minFeeRateBps ?? 1n,
  } satisfies ExchangeConfig
}
