import type { ContractFunctionParameters, Hex, PublicClient } from 'viem'
import { conditionalTokenAbi } from '../../abis/conditionalToken'
import { addresses } from '../../constants/addresses'

export async function readPayout(
  publicClient: PublicClient,
  conditionId: Hex,
): Promise<[bigint[], bigint]> {
  const chainId = publicClient.chain?.id as keyof typeof addresses
  if (!chainId) throw new Error('ChainId Not Found')

  const conditionalTokensAddress = addresses[chainId].conditionalTokens

  if (!conditionalTokensAddress)
    throw new Error('Conditional Tokens Address Not Found')

  const denominatorCall = {
    address: conditionalTokensAddress,
    abi: conditionalTokenAbi,
    functionName: 'payoutDenominator',
    args: [conditionId],
  } as ContractFunctionParameters<
    typeof conditionalTokenAbi,
    'view',
    'payoutDenominator'
  >

  const outcomeSlotCountCall = {
    address: conditionalTokensAddress,
    abi: conditionalTokenAbi,
    functionName: 'getOutcomeSlotCount',
    args: [conditionId],
  } as ContractFunctionParameters<
    typeof conditionalTokenAbi,
    'view',
    'getOutcomeSlotCount'
  >

  const results = await publicClient.multicall({
    contracts: [denominatorCall, outcomeSlotCountCall],
    allowFailure: false,
  })

  const [payoutDenominator, outcomeSlotCount] = results as [bigint, bigint]

  const numeratorsCalls = Array.from(
    { length: Number(outcomeSlotCount) },
    (_, i) =>
      ({
        address: conditionalTokensAddress,
        abi: conditionalTokenAbi,
        functionName: 'payoutNumerators',
        args: [conditionId, BigInt(i)],
      }) as ContractFunctionParameters<
        typeof conditionalTokenAbi,
        'view',
        'payoutNumerators'
      >,
  )

  const numeratorsResults = await publicClient.multicall({
    contracts: numeratorsCalls,
    allowFailure: false,
  })

  return [numeratorsResults, payoutDenominator]
}
