import type { Address, TypedDataDomain } from 'viem'
import { addresses } from '../constants/addresses'
import {
  CTF_EXCHANGE_EIP712_NAME,
  CTF_EXCHANGE_EIP712_VERSION,
} from '../constants/eip712'

export function getCtfExchangeEip712Domain(
  chainId: number,
  verifyingContract?: Address,
): TypedDataDomain {
  if (!verifyingContract) {
    verifyingContract = addresses[chainId]?.ctfExchange
  }
  if (!verifyingContract) {
    throw new Error('CTF Exchange Address Not Found')
  }
  return {
    name: CTF_EXCHANGE_EIP712_NAME,
    version: CTF_EXCHANGE_EIP712_VERSION,
    chainId,
    verifyingContract,
  }
}
