import {
  type Address,
  encodeFunctionData,
  encodePacked,
  getCreate2Address,
  keccak256,
  pad,
} from 'viem'
import { addresses } from '../../../constants/addresses'

export function getProbProxyWalletAddress(
  chainId: number,
  signer: Address,
): Address {
  const probProxyFactoryAddress = addresses[chainId]?.probProxyFactory
  const probProxyImplementationAddress =
    addresses[chainId]?.probProxyImplementation
  if (!probProxyFactoryAddress || !probProxyImplementationAddress) {
    throw new Error('Prob Proxy Factory or Implementation Address Not Found')
  }
  return getCreate2Address({
    from: probProxyFactoryAddress,
    salt: keccak256(encodePacked(['address'], [signer])),
    bytecodeHash: computeByteCodeHash(
      probProxyFactoryAddress,
      probProxyImplementationAddress,
    ),
  })
}

/**
 * Compute the creation bytecode for the proxy wallet
 * @param deployer - Factory contract address
 * @param target - Implementation contract address
 * @returns Creation bytecode
 */
function computeCreationCode(
  deployer: `0x${string}`,
  target: `0x${string}`,
): Uint8Array {
  // Create a 99-byte buffer (corresponds to new bytes(99) in Solidity)
  const buffer = new Uint8Array(99)

  // mstore(add(buffer, 0x20), ...) - Write to the start of the data section (index 0)
  // 0x3d3d606380380380913d393d73bebebebebebebebebebebebebebebebebebebe (32 bytes)
  const part1 = Buffer.from(
    '3d3d606380380380913d393d73bebebebebebebebebebebebebebebebebebebe',
    'hex',
  )
  buffer.set(part1, 0)

  // mstore(add(buffer, 0x2d), mul(deployer, 0x01000000000000000000000000))
  // 0x2d - 0x20 = 13, so start from index 13
  // The mul operation shifts the address left by 12 bytes, so the address will occupy 32 bytes, but we only need the lower 20 bytes
  const deployerBytes = Buffer.from(
    pad(deployer.toLowerCase() as `0x${string}`, { size: 20 }).slice(2),
    'hex',
  )
  // Note: After the mul operation, the address is in the high bits of 32 bytes, so we need to write from position 13
  // But actually, due to the left shift, the high bytes of the address should be at position 13, and the low bytes at position 13+12=25
  // But Solidity's mstore will write the full 32 bytes, we only care about the actually used part here
  buffer.set(deployerBytes, 13)

  // mstore(add(buffer, 0x41), ...) - 0x41 - 0x20 = 33
  // 0x5af4602a57600080fd5b602d8060366000396000f3363d3d373d3d3d363d73be (32 bytes)
  const part2 = Buffer.from(
    '5af4602a57600080fd5b602d8060366000396000f3363d3d373d3d3d363d73be',
    'hex',
  )
  buffer.set(part2, 33)

  // mstore(add(buffer, 0x60), mul(target, 0x01000000000000000000000000))
  // 0x60 - 0x20 = 64
  const targetBytes = Buffer.from(
    pad(target.toLowerCase() as `0x${string}`, { size: 20 }).slice(2),
    'hex',
  )
  buffer.set(targetBytes, 64)

  // mstore(add(buffer, 116), ...) - 116 - 0x20 = 84
  // 0x5af43d82803e903d91602b57fd5bf30000000000000000000000000000000000 (32 bytes)
  // But the buffer is only 99 bytes, so from index 84 we can only write 15 bytes
  // Actually, this value should be 32 bytes, but the buffer is only 99 bytes, so only part of it may be written
  // Let me check: 84 + 32 = 116, but the buffer is only 99 bytes, so it will overflow!
  // Actually, Solidity's mstore will write 32 bytes, even if it exceeds the buffer's range
  // But in TypeScript, we need to ensure no overflow
  const part3 = Buffer.from(
    '5af43d82803e903d91602b57fd5bf30000000000000000000000000000000000',
    'hex',
  )
  // Only write the remaining part of the buffer (99 - 84 = 15 bytes)
  buffer.set(part3.slice(0, 15), 84)

  // Encode consData: abi.encodeWithSignature("cloneConstructor(bytes)", new bytes(0))
  const consData = encodeFunctionData({
    abi: [
      {
        name: 'cloneConstructor',
        type: 'function',
        inputs: [{ name: 'data', type: 'bytes' }],
        outputs: [],
        stateMutability: 'nonpayable',
      },
    ],
    functionName: 'cloneConstructor',
    args: ['0x' as `0x${string}`],
  })

  // Remove 0x prefix
  const consDataBytes = Buffer.from(consData.slice(2), 'hex')

  // Concatenate buffer and consData
  // Note: In Solidity, mstore may write beyond the buffer's range
  // But abi.encodePacked will only use the actual content of the buffer (99 bytes)
  // So we need to ensure the buffer is a complete 99 bytes
  const creationCode = new Uint8Array(buffer.length + consDataBytes.length)
  creationCode.set(buffer, 0)
  creationCode.set(consDataBytes, buffer.length)

  return creationCode
}

/**
 * Compute the keccak256 hash of the bytecode
 * @param deployer - Factory contract address
 * @param target - Implementation contract address
 * @returns The keccak256 hash of the bytecode
 */
export function computeByteCodeHash(
  deployer: `0x${string}`,
  target: `0x${string}`,
): `0x${string}` {
  const creationCode = computeCreationCode(deployer, target)
  return keccak256(creationCode)
}
