import { type Hex, hashTypedData } from 'viem'
import type { OrderStruct } from '../../../structs'
import { getOrderTypedData } from './getOrderTypedData'

export function hashOrder(chainId: number, order: OrderStruct): Hex {
  if (!chainId) {
    throw new Error('Chain ID Not Found')
  }
  return hashTypedData(getOrderTypedData(chainId, order))
}
