import type { Hex, PublicClient } from 'viem'
import { ctfExchangeAbi } from '../../../abis/ctfExchange'
import { getAddressFromClient } from '../../../utils/getAddressFromClient'

export type OrderStatus = {
  isFilledOrCancelled: boolean
  remaining: bigint
}

export async function getOrderStatus(
  publicClient: PublicClient,
  orderHash: Hex,
): Promise<OrderStatus> {
  const exchangeAddress = getAddressFromClient(publicClient, 'ctfExchange')
  if (!exchangeAddress) throw new Error('Exchange Address Not Found')

  const orderStatus = await publicClient.readContract({
    address: exchangeAddress,
    abi: ctfExchangeAbi,
    functionName: 'getOrderStatus',
    args: [orderHash],
  })

  return orderStatus
}
