import {
  type Address,
  fromBytes,
  type Hex,
  hexToBytes,
  type PublicClient,
} from 'viem'
import { umaCrossChainAdapterAbi } from '../../abis/umaCrossChainAdapter'
import { umaCrossChainAdapterAddresses } from '../../constants/addresses'

export type QuestionData = {
  requestTimestamp: number
  reward: bigint
  proposalBond: bigint
  liveness: number
  manualResolutionTimestamp: number
  resolved: boolean
  paused: boolean
  reset: boolean
  refund: boolean
  rewardToken: Address
  creator: Address
  ancillaryData: string
  ancillaryDataUpdates: string[]
}

const toUtf8 = (hex: Hex): string => fromBytes(hexToBytes(hex), 'string')

export async function getQuestionData(
  publicClient: PublicClient,
  questionId: Hex,
): Promise<QuestionData> {
  const adapterAddress =
    umaCrossChainAdapterAddresses[publicClient.chain?.id as number]
  if (!adapterAddress) {
    throw new Error('UMA Cross Chain Adapter Address Not Found')
  }

  const questionData = await publicClient.readContract({
    address: adapterAddress,
    abi: umaCrossChainAdapterAbi,
    functionName: 'getQuestion',
    args: [questionId],
  })

  const updates = await publicClient.readContract({
    address: adapterAddress,
    abi: umaCrossChainAdapterAbi,
    functionName: 'getUpdates',
    args: [questionId, questionData.creator],
  })

  return {
    ...questionData,
    requestTimestamp: Number(questionData.requestTimestamp),
    manualResolutionTimestamp: Number(questionData.manualResolutionTimestamp),
    liveness: Number(questionData.liveness),
    ancillaryData: toUtf8(questionData.ancillaryData).split(',initializer:')[0],
    ancillaryDataUpdates: updates.map(update => toUtf8(update.update)),
  }
}
